mapper.select:
SELECT S1.VNENTRLON_ID /*식별번호*/ , S1.UTLINSTT_ID /*이용기관(회사) ID*/ , S1.RCMD_ENPR_BZN /*제안 기업 사업자번호*/ , S1.ETNM /*기업명*/ , S1.RPRNM /*대표자명*/ , TO_CHAR(TO_DATE(S1.COL,'YYYYMMDD'),'YYYY-MM-DD') AS COL /*설립년월일*/ , S1.ADR /*본사 주소*/ , S1.BTNM /*업종명(표준산업분류)*/ , S1.INVT_INDUTY_SE /*투자업종 구분*/ , (SELECT COM_CD_NM FROM IVBADM.TB_BOX_IVT_COM_CD_D WHERE GRP_CD_ID = 'TPBS1' AND COM_CD_ID = S1.INVT_INDUTY_SE) AS INVT_INDUTY_SE_NM /*투자업종명*/ , S1.MAIN_PRODUCT /*주요제품*/ , S1.RSPR_NM /*기업 담당자명*/ , S1.RSPR_JBCL_NM /*담당자 직책*/ , S1.RSPR_CNPL_TPN /*담당자 연락처*/ , S1.RSPR_EAD /*담당자 이메일*/ , S1.ENTRPRS_CMPTPW /*기업 경쟁력 또는성장가능성*/ , S1.FLLWINVT_POSBLTY_EXPECT_ERA /*후속투자 가능성 및예상시기*/ , S1.INVT_DTLS_INVT_INSTT /*투자내역_투자기관*/ , S1.INVT_DTLS_INVT_PNTTM /*투자내역_투자라운드(직전)*/ , S1.INVT_DTLS_INVT_AMOUNT /*투자내역_투자금액(원)*/ , DECODE(S1.INVT_DTLS_INVT_DE, ' ','',TO_CHAR(TO_DATE(S1.INVT_DTLS_INVT_DE,'YYYYMMDD'),'YYYY-MM-DD')) AS INVT_DTLS_INVT_DE /*투자내역_투자일자(직전)*/ , S1.INVT_DTLS_STKPC /*투자내역_주당가격(원)*/ , S1.INVT_DTLS_ETVL_AMT /*투자내역_기업가치(원)*/ , S1.INVT_DTLS_INVT_KND /*투자내역_투자종류*/ , S1.INVT_DTLS_RM /*투자내역_비고*/ , S1.CHRG_AUDOFIR_RSPR_NM /*담당심사역_담당자이름*/ , S1.CHRG_AUDOFIR_RSPR_JBCL_NM /*담당심사역_담당자직책*/ , S1.CHRG_AUDOFIR_RSPR_CNPL_TPN /*담당심사역_담당자연락처 */ , S1.CHRG_AUDOFIR_RSPR_EAD /*담당심사역_담당자이메일*/ , S1.CONTACT_AUDOFIR_RSPR_NM /*연락담당자_담당자이름*/ , S1.CONTACT_AUDOFIR_RSPR_JBCL_NM /*연락담당자_담당자직책*/ , S1.CONTACT_AUDOFIR_RSPR_CNPL_TPN /*연락담당자_담당자연락처 */ , S1.CONTACT_AUDOFIR_RSPR_EAD /*연락담당자_담당자이메일 */ , S1.RECOMEND_IBK_BUZPLC /*추천 기업은행 영업점*/ , S1.RECOMEND_STTUS AS RECOMEND_STTUS /*추천 진행 상태*/ , S1.INVT_FACT_PRUF_PAPERS_ATCH /*투자사실 증빙 서류 첨부*/ , S1.INVT_ANALS_REPRT_ATCH /*투자분석 보고서(투자심사자료) 첨부*/ , S1.ETC_FILE_ATCH /*기타 파일 첨부*/ , S1.RGSN_TS /*등록일*/ , S1.RGSN_USER_ID /*동록자 ID*/ , S1.AMNN_TS /*수정일*/ , S1.AMNN_USER_ID /*수정자 ID*/ , S1.INVT_INSTT_DLIV_MSG /*투자기관에 전달할 메시지*/ , S1.EMAIL_SNDNG_YN /*이메일 발송 여부*/ , S1.SMS_SNDNG_YN /*sms 발송 여부*/ , NVL(TRIM(S1.DTA_PRESENTN_YN), 'N') AS DTA_PRESENTN_YN /*자료제출 여부*/ , BPR_IDX_NO /*BPR 인덱스 넘버*/ FROM TB_BOX_IVT_VNENTRLON_REQST_BASS_M S1 WHERE 1=1
AND S1.RCMD_ENPR_BZN = #{rcmdEnprBzn}
AND S1.VNENTRLON_ID = #{vnentrlonId}

SELECT S1.VNENTRLON_ID /* */ , S1.UTLINSTT_ID /*이용기관(회사) ID */ , S1.BIZRNO /*사업자등록증 파일 */ , S1.VAT_STDTAX_PROOF /*부가세과세표준증명원 (최근 3개년도) */ , S1.CPR_RGIST_MATTER_ALL_CRTF /*법인등기사항전부증명서 */ , S1.STCH_INFO_MNGM_NO /*주주명부 */ , S1.CMPNY_INTRCN /*회사소개서(IR자료) */ , S1.ETNM /*기업명 */ , S1.RPRNM /*대표자명 */ , S1.BZN /*사업자번호 */ , S1.COL /*설립년월일 */ , S1.ADR /*본사 주소 */ , S1.RSPR_NM /*기업 담당자명 */ , S1.RSPR_JBCL_NM /*담당자 직책 */ , S1.RSPR_CNPL_TPN /*담당자 연락처 */ , S1.RSPR_EAD /*담당자 이메일 */ , S1.INNF_INQ_COSN /*개인(신용)정보 조회동의서 다운로드 url */ , S1.INNF_CLUS_COSN /*개인(신용)정보 수집 이용 동의서 url */ , S1.ATCSC_ATCHMNFL /*정관 첨부파일 url */ , S1.GMTSCK_ANACT /*주주총회 또는 이사회 결의서 url */ , S1.RECOMEND_STTUS_CM /*추천상태*/ , S1.RECOMEND_STTUS_CM_RM /*추천상태 비고시 입력값*/ , S1.RGSN_TS /*등록일 */ , S1.RGSN_USER_ID /*동록자 ID */ , S1.AMNN_TS /*수정일 */ , S1.AMNN_USER_ID /*수정자 ID */ FROM TB_BOX_IVT_VNENT_RLON_APLC_RGSN_M S1 WHERE 1=1
AND S1.BZN = #{bzn}
AND S1.VNENTRLON_ID = #{vnentrlonId}

mapper.insert:
INSERT INTO TB_BOX_IVT_VNENT_RLON_APLC_RGSN_M
(
    VNENTRLON_ID
    , UTLINSTT_ID
    , RECOMEND_STTUS_CM
    , BZN
    , RGSN_USER_ID
    , RGSN_TS
    , AMNN_USER_ID
    , AMNN_TS
)
values
(
    #{params.vnentrlonId}
    , #{params.utlinsttId}
    , 'RST01004'
    , #{params.rcmdEnprBzn}
    , #{params.rgsnUserId}
    , CURRENT_TIMESTAMP
    , #{params.amnnUserId}
    , CURRENT_TIMESTAMP
)

mapper.update:
UPDATE TB_BOX_IVT_VNENTRLON_REQST_BASS_M
SET
    RECOMEND_STTUS      = #{params.recomendSttus}

   	, INVT_INSTT_DLIV_MSG = #{params.invtInsttDlivMsg}	


   	, EMAIL_SNDNG_YN = #{params.emailSndngYn}	


    , SMS_SNDNG_YN = #{params.smsSndngYn}	


    , AMNN_USER_ID  = #{params.amnnUserId}
    , AMNN_TS       = CURRENT_TIMESTAMP
WHERE 1=1
AND VNENTRLON_ID = #{params.vnentrlonId}

UPDATE TB_BOX_IVT_VNENT_RLON_APLC_RGSN_M
SET
    RECOMEND_STTUS_CM      = #{params.recomendSttusCm}

    	,RECOMEND_STTUS_CM_RM = #{params.recomendSttusCmRm}

    , AMNN_USER_ID  = #{params.amnnUserId}
    , AMNN_TS       = CURRENT_TIMESTAMP
WHERE 1=1
AND VNENTRLON_ID = #{params.vnentrlonId}

		MERGE INTO TB_BOX_IVT_AGREM_VNENTR_INVT_MANAGE_M m
            USING DUAL ON (m.AGREM_VNENTR_SEQ = #{agremVnentrSeq})
        WHEN MATCHED THEN
			 UPDATE 
		        SET
		          INVM_ENPR_NM = #{invmEnprNm}
				, BZN = #{bzn}


	       		, ADR = #{adr}	


	       		, ADR = ' '




	       		 , AGREM_YN = #{agremYn}


	       		, AGREM_YN = ' '




	       		 , AGREM_CNCLSDE = #{agremCnclsde}


	       		, AGREM_CNCLSDE = ' '




	       		, AGREM_EXPRTNDE = #{agremExprtnde}


	       		, AGREM_EXPRTNDE = ' '




	       		, AGRMNT_ATCHMNFL = #{agrmntAtchmnfl}


	       		, AGRMNT_ATCHMNFL = ' '


				, CONTACT_RSPR_ONE_NM = #{contactRsprOneNm}
				, CONTACT_RSPR_ONE_CNPL_TPN = #{contactRsprOneCnplTpn}


	       		, CONTACT_RSPR_ONE_EAD = #{contactRsprOneEad}


	       		, CONTACT_RSPR_ONE_EAD = ' '


				, CONTACT_RSPR_TWO_NM = #{contactRsprTwoNm}
				, CONTACT_RSPR_TWO_CNPL_TPN = #{contactRsprTwoCnplTpn}


	       		, CONTACT_RSPR_TWO_EAD = #{contactRsprTwoEad}


	       		, CONTACT_RSPR_TWO_EAD = ' '


		        , AMNN_USER_ID  = #{amnnUserId}
		        , AMNN_TS       = CURRENT_TIMESTAMP
		        WHERE 1=1
		        AND AGREM_VNENTR_SEQ = #{agremVnentrSeq}
       	WHEN NOT MATCHED THEN
	       INSERT 
	       (
	          AGREM_VNENTR_SEQ
			, INVM_ENPR_NM
			, BZN
			, ADR
			, AGREM_YN
			, AGREM_CNCLSDE
			, AGREM_EXPRTNDE
			, AGRMNT_ATCHMNFL
			, CONTACT_RSPR_ONE_NM
			, CONTACT_RSPR_ONE_CNPL_TPN
			, CONTACT_RSPR_ONE_EAD
			, CONTACT_RSPR_TWO_NM
			, CONTACT_RSPR_TWO_CNPL_TPN
			, CONTACT_RSPR_TWO_EAD
			, RGSN_TS
			, RGSN_USER_ID

	       )
	       values
	       (
	           (SELECT NVL(MAX(AGREM_VNENTR_SEQ), 0) + 1
	            FROM TB_BOX_IVT_AGREM_VNENTR_INVT_MANAGE_M)
	        , #{invmEnprNm}
	   	    , #{bzn}


		       		, #{adr}	


		       		, ' '




		       		 , #{agremYn}


		       		, ' '




		       		  , #{agremCnclsde}


		       		, ' '




		       		 , #{agremExprtnde}


		       		, ' '




		       		 , #{agrmntAtchmnfl}


		       		, ' '


	        , #{contactRsprOneNm}
	        , #{contactRsprOneCnplTpn}


		       		 , #{contactRsprOneEad}


		       		, ' '


	        , #{contactRsprTwoNm}
	        , #{contactRsprTwoCnplTpn}


		       		 , #{contactRsprTwoEad}


		       		, ' '


	        , CURRENT_TIMESTAMP


		       		 , #{rgsnUserId}


		       		, ' '



	       )

UPDATE TB_BOX_IVT_VNENTRLON_REQST_BASS_M
SET
    BPR_IDX_NO      = #{params.bprIdxNo}
WHERE 1=1
AND VNENTRLON_ID = #{params.vnentrlonId}
